const aiResponse = $input.item.json.choices[0].message.content;

// JSON repair function for common LLM mistakes
function repairJson(str) {
    let s = str.trim();
    // Remove markdown code blocks
    s = s.replace(/^```json\s*\n?|\n?```$/g, '');
    // Fix common bracket issues: }] -> }] and ]} -> }]
    // Count brackets to detect imbalance
    let opens = { '{': 0, '[': 0 };
    let closes = { '}': 0, ']': 0 };
    for (const c of s) {
        if (c === '{') opens['{']++;
        if (c === '[') opens['[']++;
        if (c === '}') closes['}']++;
        if (c === ']') closes[']']++;
    }
    // Add missing closing brackets
    while (closes['}'] < opens['{']) { s += '}'; closes['}']++; }
    while (closes[']'] < opens['[']) { s += ']'; closes[']']++; }
    // Fix pattern: \"...\"\n    ] where } is missing before ]
    s = s.replace(/(\"[^\"]*\")\s*\n?\s*\]/g, (match, p1) => {
        // Check if we need a } before ]
        const beforeMatch = s.substring(0, s.indexOf(match));
        const lastOpen = Math.max(beforeMatch.lastIndexOf('{'), beforeMatch.lastIndexOf('['));
        if (beforeMatch[lastOpen] === '{') {
            return p1 + '}]';
        }
        return match;
    });
    return s;
}

let parsedData;
try {
    parsedData = JSON.parse(aiResponse);
} catch (e) {
    try {
        const repaired = repairJson(aiResponse);
        parsedData = JSON.parse(repaired);
    } catch (e2) {
        throw new Error('JSON parse failed: ' + e.message + ' | Repaired attempt: ' + e2.message);
    }
}

// Generate unique slug with timestamp to prevent duplicates
const uniqueSlug = parsedData.slug + '-' + Date.now().toString(36);

// Helper to normalize prompt objects
const normalize = (p) => {
    if (!p || typeof p !== 'object') return { type: '', prompt: '' };
    const typeKey = Object.keys(p).find(k => k.toLowerCase() === 'type');
    const promptKey = Object.keys(p).find(k => k.toLowerCase() === 'prompt');
    return {
        type: typeKey ? String(p[typeKey]).trim().toLowerCase() : '',
        prompt: promptKey ? p[promptKey] : ''
    };
};

const normalizedPrompts = (parsedData.image_prompts || []).map(normalize);

return {
    json: {
        ...parsedData,
        slug: uniqueSlug,
        featured_prompt: (normalizedPrompts.find(p => p.type === 'featured') || {}).prompt,
        inline_prompts: normalizedPrompts.filter(p => p.type === 'inline')
    }
};

const allItems = $input.all();
const urls = allItems.map(item => item.json.media.url);
return [{ json: { urls } }];

const contentData = $("Parse AI Response1").first().json;
const featuredImg = $("Upload Featured Image1").first().json.media.url;

// Get inline image URLs from the Aggregate Images node
const aggregateData = $("Aggregate Images1").first().json;
const inlineImgs = aggregateData.urls || [];

let finalContent = contentData.content;

inlineImgs.forEach((url, index) => {
    const placeholder = `<<IMAGE_PLACEHOLDER_${index + 1}>>`;
    const markdownImage = `![Blog Image](${url})`;
    finalContent = finalContent.replace(placeholder, markdownImage);
});

// Cleanup unused placeholders
finalContent = finalContent.replace(/<<IMAGE_PLACEHOLDER_\d+>>/g, '');

return [{
    json: {
        title: contentData.title,
        slug: contentData.slug,
        excerpt: contentData.excerpt,
        featuredImage: featuredImg,
        seo_title: contentData.seo_title,
        seo_description: contentData.seo_description,
        seo_keywords: contentData.seo_keywords,
        content: finalContent,
        is_published: true
    }
}];

const resultJson = JSON.parse($input.item.json.data.resultJson);
const url = resultJson.resultUrls[0];
return [{ json: { url } }];

// Collect all taskIds from Kie.ai Submit responses into a single item
const allItems = $input.all();
const taskIds = allItems.map(item => item.json.data.taskId);

// Reset static data for fresh run
const staticData = $getWorkflowStaticData('global');
staticData.collectedUrls = [];

return [{ json: { taskIds, collectedUrls: [] } }];

// Prepare items for status check - split taskIds back into individual items
const { taskIds, collectedUrls } = $input.first().json;

// Store collectedUrls in static data (HTTP Request will overwrite input data)
const staticData = $getWorkflowStaticData('global');
staticData.collectedUrls = collectedUrls || [];

return taskIds.map(taskId => ({ json: { taskId } }));

// Aggregate all status check results and determine completion
const allItems = $input.all();

// Get collectedUrls from static data (preserved across HTTP request)
const staticData = $getWorkflowStaticData('global');
const collectedUrls = staticData.collectedUrls || [];

const newUrls = [];
const pendingTaskIds = [];

for (const item of allItems) {
  const state = item.json.data?.state;
  // taskId is in the Kie.ai response, not our input (HTTP overwrites input)
  const taskId = item.json.data?.taskId;

  if (state === 'success') {
    try {
      const resultJson = JSON.parse(item.json.data.resultJson);
      newUrls.push(resultJson.resultUrls[0]);
    } catch (e) {
      if (taskId) pendingTaskIds.push(taskId);
    }
  } else if (taskId) {
    pendingTaskIds.push(taskId);
  }
}

const allUrls = [...collectedUrls, ...newUrls];
const allComplete = pendingTaskIds.length === 0;

// Update static data for next iteration
staticData.collectedUrls = allUrls;

return [{
  json: {
    allComplete,
    urls: allUrls,
    taskIds: pendingTaskIds,
    collectedUrls: allUrls
  }
}];

// Extract URLs and split into individual items for download
const urls = $input.first().json.urls;
return urls.map(url => ({ json: { url } }));
